import { useEffect } from 'react';
import { isAutoSync, getCloudUrl, pullAll, pushAll } from './cloudSync';

// When auto-sync is on and a spreadsheet is connected: pull the latest on app start,
// and push this device's data whenever the app is backgrounded/closed. Last write wins.
export default function useCloudAutoSync() {
  useEffect(() => {
    if (!isAutoSync() || !getCloudUrl()) return;

    pullAll().catch(() => {});

    const pushIfHidden = () => {
      if (document.visibilityState === 'hidden') pushAll().catch(() => {});
    };
    const pushNow = () => { pushAll().catch(() => {}); };

    document.addEventListener('visibilitychange', pushIfHidden);
    window.addEventListener('pagehide', pushNow);
    return () => {
      document.removeEventListener('visibilitychange', pushIfHidden);
      window.removeEventListener('pagehide', pushNow);
    };
  }, []);
}
