import { useState, useEffect, useRef } from 'react';
import { Search, Star, Plus, Camera, ChefHat, Zap, Globe, Loader } from 'lucide-react';
import { searchFoods } from './nutrition';
import { getAllFoods, getRecentFoods, getFavoriteFoods, toggleFavorite, saveFood } from './db';
import { searchOFF } from './openfoodfacts';
import ServingEditorModal from './ServingEditorModal';
import CustomFoodModal from './CustomFoodModal';
import BarcodeScanner from './BarcodeScanner';
import RecipeModal from './RecipeModal';
import QuickAddModal from './QuickAddModal';

const CATEGORY_EMOJI = {
  protein: '🥩', dairy: '🥛', grain: '🌾', vegetable: '🥦',
  fruit: '🍎', fat: '🫒', beverage: '☕', supplement: '💊', other: '🟤',
};

const TABS = ['recent', 'favorites', 'all'];

export default function FoodPickerModal({ meals, defaultMealId, onLog, onClose }) {
  const [tab,        setTab]        = useState('recent');
  const [query,      setQuery]      = useState('');
  const [allFoods,   setAllFoods]   = useState([]);
  const [recent,     setRecent]     = useState([]);
  const [favs,       setFavs]       = useState([]);
  const [results,    setResults]    = useState([]);
  const [favSet,     setFavSet]     = useState(new Set());
  const [selected,   setSelected]   = useState(null);
  const [showCustom, setShowCustom] = useState(false);
  const [showScan,   setShowScan]   = useState(false);
  const [showRecipe, setShowRecipe] = useState(false);
  const [showQuick,  setShowQuick]  = useState(false);
  const [online,     setOnline]     = useState([]);
  const [onlineState, setOnlineState] = useState('idle'); // idle | loading | done | error
  const debounceRef = useRef(null);
  const inputRef    = useRef(null);

  useEffect(() => {
    (async () => {
      const [all, rec, fv] = await Promise.all([getAllFoods(), getRecentFoods(), getFavoriteFoods()]);
      setAllFoods(all);
      setRecent(rec);
      setFavs(fv);
      setFavSet(new Set(fv.map(f => f.id)));
    })();
    setTimeout(() => inputRef.current?.focus(), 100);
  }, []);

  useEffect(() => {
    if (debounceRef.current) clearTimeout(debounceRef.current);
    setOnline([]); setOnlineState('idle');
    if (!query.trim()) { setResults([]); return; }
    debounceRef.current = setTimeout(() => {
      setResults(searchFoods(allFoods, query).slice(0, 50));
      setTab('all');
    }, 200);
  }, [query, allFoods]);

  async function handleSearchOnline() {
    const q = query.trim();
    if (!q) return;
    setOnlineState('loading');
    try {
      const found = await searchOFF(q);
      setOnline(found);
      setOnlineState('done');
    } catch {
      setOnlineState('error');
    }
  }

  // Persist an online result to the local DB so it gets an id (and lands in Recent),
  // then open the serving editor for it.
  async function handlePickOnline(food) {
    const id = await saveFood(food);
    const saved = { ...food, id };
    setAllFoods(prev => prev.find(f => f.id === id) ? prev : [saved, ...prev]);
    setSelected(saved);
  }

  const displayList = query.trim()
    ? results
    : tab === 'recent'    ? recent
    : tab === 'favorites' ? favs
    : allFoods;

  async function handleToggleFav(e, foodId) {
    e.stopPropagation();
    const isNowFav = await toggleFavorite(foodId);
    setFavSet(prev => {
      const next = new Set(prev);
      isNowFav ? next.add(foodId) : next.delete(foodId);
      return next;
    });
    if (!isNowFav && tab === 'favorites') {
      setFavs(prev => prev.filter(f => f.id !== foodId));
    } else if (isNowFav) {
      const food = allFoods.find(f => f.id === foodId);
      if (food) setFavs(prev => [food, ...prev.filter(f => f.id !== foodId)]);
    }
  }

  async function handleLog(entryData) {
    await onLog(entryData);
    setSelected(null);
    const rec = await getRecentFoods();
    setRecent(rec);
  }

  async function handleCustomSaved(food) {
    setAllFoods(prev => [food, ...prev]);
    setShowCustom(false);
    setSelected(food);
  }

  async function handleRecipeSaved(food) {
    setAllFoods(prev => [food, ...prev]);
    setShowRecipe(false);
    setSelected(food);
  }

  function handleBarcodeFound(food) {
    setShowScan(false);
    // Merge into allFoods if not already present
    setAllFoods(prev => prev.find(f => f.id === food.id) ? prev : [food, ...prev]);
    setSelected(food);
  }

  function handleBarcodeNotFound(barcode) {
    setShowScan(false);
    setShowCustom(true);
  }

  // Sub-modal: barcode
  if (showScan) {
    return (
      <div className="nc-modal-overlay">
        <div className="nc-picker">
          <div className="nc-picker-header">
            <div className="nc-picker-title-row">
              <span className="nc-picker-title">Scan Barcode</span>
              <button className="nc-picker-close" onClick={() => setShowScan(false)}>✕</button>
            </div>
          </div>
          <div className="nc-picker-list">
            <BarcodeScanner onFound={handleBarcodeFound} onNotFound={handleBarcodeNotFound} />
          </div>
        </div>
      </div>
    );
  }

  // Sub-modal: custom food
  if (showCustom) {
    return (
      <div className="nc-modal-overlay">
        <CustomFoodModal meals={meals} onSaved={handleCustomSaved} onClose={() => setShowCustom(false)} />
      </div>
    );
  }

  // Sub-modal: recipe builder
  if (showRecipe) {
    return <RecipeModal onClose={() => setShowRecipe(false)} onSaved={handleRecipeSaved} />;
  }

  // Sub-modal: quick add
  if (showQuick) {
    return (
      <QuickAddModal
        meals={meals}
        defaultMealId={defaultMealId}
        onLog={async (ed) => { await onLog(ed); setShowQuick(false); }}
        onClose={() => setShowQuick(false)}
      />
    );
  }

  // Sub-modal: serving editor
  if (selected) {
    return (
      <div className="nc-modal-overlay">
        <ServingEditorModal
          food={selected}
          meals={meals}
          onLog={handleLog}
          onBack={() => setSelected(null)}
        />
      </div>
    );
  }

  return (
    <div className="nc-modal-overlay" onClick={e => { if (e.target === e.currentTarget) onClose(); }}>
      <div className="nc-picker">
        <div className="nc-picker-header">
          <div className="nc-picker-title-row">
            <span className="nc-picker-title">Add Food</span>
            <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
              <button
                title="Scan barcode"
                style={{ color: 'var(--nc-text2)', display: 'flex', alignItems: 'center' }}
                onClick={() => setShowScan(true)}
              >
                <Camera size={20} />
              </button>
              <button className="nc-picker-close" onClick={onClose}>✕</button>
            </div>
          </div>

          <div className="nc-search-bar">
            <Search size={15} className="nc-search-icon" />
            <input
              ref={inputRef}
              placeholder="Search foods…"
              value={query}
              onChange={e => setQuery(e.target.value)}
            />
            {query && (
              <button className="nc-search-clear" onClick={() => setQuery('')}>✕</button>
            )}
          </div>

          {!query.trim() && (
            <div className="nc-picker-tabs">
              {TABS.map(t => (
                <button
                  key={t}
                  className={`nc-picker-tab${tab === t ? ' active' : ''}`}
                  onClick={() => setTab(t)}
                >
                  {t.charAt(0).toUpperCase() + t.slice(1)}
                </button>
              ))}
            </div>
          )}
        </div>

        <div className="nc-picker-list">
          {displayList.length === 0 ? (
            <div className="nc-picker-empty">
              {query.trim()
                ? `No results for "${query}"`
                : tab === 'favorites' ? 'No favorites yet — tap ★ on any food'
                : tab === 'recent'   ? 'No foods logged yet'
                : 'No foods'}
            </div>
          ) : (
            displayList.map(food => (
              <div key={food.id} className="nc-food-row" onClick={() => setSelected(food)}>
                <div className={`nc-food-icon cat-${food.category}`}>
                  {CATEGORY_EMOJI[food.category] || '🍽️'}
                </div>
                <div className="nc-food-body">
                  <div className="nc-food-name">{food.name}</div>
                  {food.brand && <div className="nc-food-brand">{food.brand}</div>}
                </div>
                <div className="nc-food-meta">
                  <div className="nc-food-kcal">{Math.round(food.kcal)}</div>
                  <div className="nc-food-per">kcal/100g</div>
                </div>
                <button
                  className={`nc-fav-btn${favSet.has(food.id) ? ' active' : ''}`}
                  onClick={e => handleToggleFav(e, food.id)}
                >
                  <Star size={15} fill={favSet.has(food.id) ? 'currentColor' : 'none'} />
                </button>
              </div>
            ))
          )}

          {/* Online search (Open Food Facts) — surfaced whenever the user is searching */}
          {query.trim() && (
            <div style={{ padding: '10px 0' }}>
              {onlineState !== 'done' && (
                <button
                  className="nc-add-custom-btn"
                  onClick={handleSearchOnline}
                  disabled={onlineState === 'loading'}
                  style={{ justifyContent: 'center', color: 'var(--nc-accent)' }}
                >
                  {onlineState === 'loading'
                    ? <><Loader size={16} className="nc-spin" /> Searching online…</>
                    : <><Globe size={16} /> Search Open Food Facts</>}
                </button>
              )}
              {onlineState === 'error' && (
                <div className="nc-picker-empty" style={{ padding: '10px 0' }}>Couldn’t reach Open Food Facts.</div>
              )}
              {onlineState === 'done' && (
                <>
                  <div style={{ fontSize: 11, fontWeight: 700, color: 'var(--nc-text3)', textTransform: 'uppercase', letterSpacing: '0.05em', padding: '6px 14px' }}>
                    Online results
                  </div>
                  {online.length === 0 ? (
                    <div className="nc-picker-empty" style={{ padding: '8px 0' }}>No online matches.</div>
                  ) : online.map((food, i) => (
                    <div key={`off-${i}`} className="nc-food-row" onClick={() => handlePickOnline(food)}>
                      <div className="nc-food-icon cat-other"><Globe size={15} /></div>
                      <div className="nc-food-body">
                        <div className="nc-food-name">{food.name}</div>
                        {food.brand && <div className="nc-food-brand">{food.brand}</div>}
                      </div>
                      <div className="nc-food-meta">
                        <div className="nc-food-kcal">{Math.round(food.kcal)}</div>
                        <div className="nc-food-per">kcal/100g</div>
                      </div>
                    </div>
                  ))}
                </>
              )}
            </div>
          )}
        </div>

        <div style={{ borderTop: '1px solid var(--nc-border)', flexShrink: 0 }}>
          <button className="nc-add-custom-btn" onClick={() => setShowQuick(true)}>
            <Zap size={16} />
            Quick Add Calories
          </button>
          <button className="nc-add-custom-btn" onClick={() => setShowRecipe(true)}>
            <ChefHat size={16} />
            Create Recipe
          </button>
          <button className="nc-add-custom-btn" onClick={() => setShowCustom(true)}>
            <Plus size={16} />
            Create Custom Food
          </button>
        </div>
      </div>
    </div>
  );
}
