// All amounts per 100g stored in DB; scale by (amountG / 100) for actual values.

export function entryKcal(entry) {
  return (entry.foodKcal * entry.amountG) / 100;
}

export function computeTotals(entries) {
  return entries.reduce(
    (acc, e) => {
      const s = e.amountG / 100;
      acc.kcal          += (e.foodKcal          || 0) * s;
      acc.proteinG      += (e.foodProteinG      || 0) * s;
      acc.carbsG        += (e.foodCarbsG        || 0) * s;
      acc.fatG          += (e.foodFatG          || 0) * s;
      acc.fiberG        += (e.foodFiberG        || 0) * s;
      // Minerals
      acc.calciumMg     += (e.foodCalciumMg     || 0) * s;
      acc.ironMg        += (e.foodIronMg        || 0) * s;
      acc.magnesiumMg   += (e.foodMagnesiumMg   || 0) * s;
      acc.potassiumMg   += (e.foodPotassiumMg   || 0) * s;
      acc.sodiumMg      += (e.foodSodiumMg      || 0) * s;
      acc.zincMg        += (e.foodZincMg        || 0) * s;
      acc.copperMg      += (e.foodCopperMg      || 0) * s;
      acc.seleniumMcg   += (e.foodSeleniumMcg   || 0) * s;
      // Vitamins
      acc.vitaminAMcg   += (e.foodVitaminAMcg   || 0) * s;
      acc.vitaminCMg    += (e.foodVitaminCMg    || 0) * s;
      acc.vitaminDMcg   += (e.foodVitaminDMcg   || 0) * s;
      acc.vitaminEMg    += (e.foodVitaminEMg    || 0) * s;
      acc.vitaminKMcg   += (e.foodVitaminKMcg   || 0) * s;
      acc.thiamineMg    += (e.foodThiamineMg    || 0) * s;
      acc.riboflavinMg  += (e.foodRiboflavinMg  || 0) * s;
      acc.niacinMg      += (e.foodNiacinMg      || 0) * s;
      acc.b6Mg          += (e.foodB6Mg          || 0) * s;
      acc.folateMcg     += (e.foodFolateMcg     || 0) * s;
      acc.b12Mcg        += (e.foodB12Mcg        || 0) * s;
      // Fatty acids
      acc.omega3G       += (e.foodOmega3G       || 0) * s;
      acc.omega6G       += (e.foodOmega6G       || 0) * s;
      return acc;
    },
    {
      kcal: 0, proteinG: 0, carbsG: 0, fatG: 0, fiberG: 0,
      calciumMg: 0, ironMg: 0, magnesiumMg: 0, potassiumMg: 0, sodiumMg: 0,
      zincMg: 0, copperMg: 0, seleniumMcg: 0,
      vitaminAMcg: 0, vitaminCMg: 0, vitaminDMcg: 0, vitaminEMg: 0, vitaminKMcg: 0,
      thiamineMg: 0, riboflavinMg: 0, niacinMg: 0, b6Mg: 0, folateMcg: 0, b12Mcg: 0,
      omega3G: 0, omega6G: 0,
    }
  );
}

export function computePreview(food, amountG) {
  const s = amountG / 100;
  return {
    kcal:     Math.round((food.kcal     || 0) * s),
    proteinG: +((food.proteinG || 0) * s).toFixed(1),
    carbsG:   +((food.carbsG   || 0) * s).toFixed(1),
    fatG:     +((food.fatG     || 0) * s).toFixed(1),
    fiberG:   +((food.fiberG   || 0) * s).toFixed(1),
  };
}

// Unit conversion to grams
const UNIT_CONVERSIONS = {
  g:       (a) => a,
  oz:      (a) => a * 28.3495,
  lb:      (a) => a * 453.592,
  kg:      (a) => a * 1000,
  mL:      (a) => a,
  'fl oz': (a) => a * 29.5735,
  cup:     (a) => a * 240,
  tbsp:    (a) => a * 14.787,
  tsp:     (a) => a * 4.929,
};

export function toGrams(amount, unit, foodServingSizeG = 100) {
  if (unit === 'serving') return amount * foodServingSizeG;
  const fn = UNIT_CONVERSIONS[unit];
  return fn ? fn(amount) : amount;
}

export const UNITS = ['g', 'oz', 'lb', 'mL', 'fl oz', 'cup', 'tbsp', 'tsp', 'serving'];

export function unitLabel(amount, unit) {
  const rounded = Number.isInteger(amount) ? amount : +amount.toFixed(1);
  return `${rounded} ${unit}`;
}

// Tokenized search — prefix match on each whitespace-separated token
export function searchFoods(foods, query) {
  const raw = query.trim().toLowerCase();
  if (!raw) return [];
  const tokens = raw.split(/\s+/).filter(Boolean);

  const matches = foods.filter(f => {
    const haystack = `${f.name} ${f.brand || ''}`.toLowerCase();
    return tokens.every(t => haystack.includes(t));
  });

  matches.sort((a, b) => {
    const aName = a.name.toLowerCase();
    const bName = b.name.toLowerCase();
    const aStarts = aName.startsWith(raw);
    const bStarts = bName.startsWith(raw);
    if (aStarts && !bStarts) return -1;
    if (!aStarts && bStarts) return 1;
    return aName.localeCompare(bName);
  });

  return matches;
}

export function fmt(n, decimals = 0) {
  return Math.round(n * Math.pow(10, decimals)) / Math.pow(10, decimals);
}
