// Offline heuristic auto-fill: guess an exercise's muscle group, equipment, and
// tracking type from its name. Always available, instant, no network. Values match the
// CreateModal dropdowns (BODY_PARTS / EQUIPMENT_LIST) and tracking options.

const has = (s, ...words) => words.some(w => s.includes(w));

// Returns { bodyPart, equipment, trackType } — any field may be '' if unsure.
export function inferExercise(rawName) {
  const s = ` ${(rawName || '').toLowerCase()} `;
  if (!s.trim()) return { bodyPart: '', equipment: '', trackType: '' };

  // ── Tracking type ──
  const isHold = has(s, 'stretch', 'plank', 'hold', 'hang', 'wall sit', 'l-sit', 'l sit',
    'hollow', 'isometric', 'pose', 'cobra', 'pigeon', 'cat-cow', 'cat cow', "child's", 'savasana',
    'balance', 'stand', 'dead hang', 'mobility');
  const trackType = isHold ? 'time' : 'weight_reps';

  // ── Equipment ──
  let equipment = '';
  if (has(s, 'barbell', 'bench press', 'deadlift', 'back squat', 'front squat', 'overhead press', 'ohp', 'clean', 'snatch')) equipment = 'barbell';
  else if (has(s, 'ez bar', 'ez-bar', 'ez curl', 'e-z')) equipment = 'ez barbell';
  else if (has(s, 'dumbbell', ' db ', 'goblet')) equipment = 'dumbbell';
  else if (has(s, 'kettlebell', 'kb ', 'turkish get')) equipment = 'kettlebell';
  else if (has(s, 'cable', 'pushdown', 'pulldown', 'lat pulldown', 'face pull')) equipment = 'cable';
  else if (has(s, 'smith')) equipment = 'smith machine';
  else if (has(s, 'machine', 'leg press', 'pec deck', 'hack squat', 'leg extension', 'leg curl')) equipment = 'leverage machine';
  else if (has(s, 'band', 'resistance band')) equipment = 'resistance band';
  else if (has(s, 'push-up', 'push up', 'pull-up', 'pull up', 'chin-up', 'chin up', 'dip', 'plank',
    'pistol', 'lunge', 'bodyweight', 'body weight', 'sit-up', 'crunch', 'stretch', 'pose', 'bridge',
    'mountain climber', 'burpee', 'handstand', 'muscle-up', 'l-sit', 'hollow', 'squat hold')) equipment = 'body weight';

  // ── Muscle group (BODY_PARTS vocabulary) ──
  let bodyPart = '';
  if (has(s, 'calf', 'calves', 'tibia')) bodyPart = 'lower legs';
  else if (has(s, 'forearm', 'wrist', 'grip', 'dead hang', 'farmer')) bodyPart = 'lower arms';
  else if (has(s, 'neck')) bodyPart = 'neck';
  else if (has(s, 'ab ', 'abs', 'core', 'plank', 'crunch', 'sit-up', 'sit up', 'oblique', 'hollow',
    'l-sit', 'l sit', 'leg raise', 'dragon flag', 'v-up', 'v up', 'russian twist')) bodyPart = 'waist';
  else if (has(s, 'squat', 'lunge', 'quad', 'hamstring', 'glute', 'leg press', 'leg curl', 'leg extension',
    'pistol', 'bridge', 'thrust', 'deadlift', 'rdl', 'step-up', 'step up', 'split squat', 'nordic')) bodyPart = 'upper legs';
  else if (has(s, 'bench', 'chest', 'fly', 'flye', 'push-up', 'push up', 'pec', 'dip')) bodyPart = 'chest';
  else if (has(s, 'row', 'pull-up', 'pull up', 'chin-up', 'chin up', 'lat', 'pulldown', 'back', 'pull down', 'deadlift')) bodyPart = 'back';
  else if (has(s, 'shoulder', 'press', 'raise', 'delt', 'pike', 'handstand', 'overhead', 'upright row', 'shrug')) bodyPart = 'shoulders';
  else if (has(s, 'curl', 'bicep', 'tricep', 'extension', 'pushdown', 'skull', 'kickback')) bodyPart = 'upper arms';
  else if (has(s, 'run', 'sprint', 'jump rope', 'cardio', 'burpee', 'jumping jack', 'mountain climber')) bodyPart = 'cardio';

  return { bodyPart, equipment, trackType };
}
