import { useState, useEffect, useRef } from 'react';
import {
  X, Cloud, Upload, Download, AlertTriangle, Check, Loader2, Copy,
  ChevronDown, ChevronRight, Link2, Trash2, FileDown, FileUp,
} from 'lucide-react';
import {
  getCloudUrl, setCloudUrl, getLastSync, isAutoSync, setAutoSync,
  testConnection, pushAll, pullAll, buildCsv, downloadCsv, parseCsv, importCsvRows,
  APPS_SCRIPT,
} from '../utils/cloudSync';

const A = '#6366F1';

// appsscript.json that restricts the OAuth scope to only the bound spreadsheet.
const MANIFEST = `{
  "timeZone": "Etc/GMT",
  "runtimeVersion": "V8",
  "exceptionLogging": "STACKDRIVER",
  "oauthScopes": ["https://www.googleapis.com/auth/spreadsheets.currentonly"],
  "webapp": { "executeAs": "USER_DEPLOYING", "access": "ANYONE_ANONYMOUS" }
}`;

export default function CloudSyncPanel({ onClose }) {
  const [url, setUrl]         = useState(getCloudUrl());
  const [connected, setConn]  = useState(!!getCloudUrl());
  const [busy, setBusy]       = useState(null);   // 'connect'|'load'|'save'|'csv'
  const [msg, setMsg]         = useState(null);   // { kind, text }
  const [confirmLoad, setCL]  = useState(false);
  const [showSetup, setSetup] = useState(!getCloudUrl());
  const [auto, setAuto]       = useState(isAutoSync());
  const [last, setLast]       = useState(getLastSync());
  const fileRef = useRef(null);

  useEffect(() => { setAutoSync(auto); }, [auto]);

  function ok(text) { setMsg({ kind: 'ok', text }); }
  function err(text) { setMsg({ kind: 'err', text }); }

  async function handleConnect() {
    if (!url.trim()) return;
    setBusy('connect'); setMsg(null);
    try {
      await testConnection(url.trim());
      setCloudUrl(url.trim());
      setConn(true); setSetup(false);
      ok('Connected. Use “Load” to pull the spreadsheet onto this device, or “Save” to upload this device’s data.');
    } catch {
      err('Couldn’t reach that link. Make sure the Web App is deployed with access set to “Anyone”, and paste the /exec URL.');
    } finally { setBusy(null); }
  }

  async function exportCsv() {
    const csv = await buildCsv();
    downloadCsv(csv);
  }

  async function doLoad() {
    setCL(false); setBusy('load'); setMsg(null);
    try {
      const { restored } = await pullAll();
      setLast(getLastSync());
      ok(`Loaded ${restored.toLocaleString()} records from the spreadsheet. Reloading…`);
      setTimeout(() => window.location.reload(), 1000);
    } catch (e) {
      err(e.message || 'Load failed.');
      setBusy(null);
    }
  }

  async function doSave() {
    setBusy('save'); setMsg(null);
    try {
      const { pushed, skipped } = await pushAll();
      setLast(getLastSync());
      ok(`Saved ${pushed.toLocaleString()} records to the spreadsheet${skipped ? ` (${skipped} large items like photos kept local only)` : ''}.`);
    } catch (e) {
      err(e.message || 'Save failed.');
    } finally { setBusy(null); }
  }

  async function handleCsvFile(e) {
    const file = e.target.files?.[0];
    e.target.value = '';
    if (!file) return;
    setBusy('csv'); setMsg(null);
    try {
      const rows = parseCsv(await file.text());
      const { merged, pushedToCloud } = await importCsvRows(rows);
      ok(`Imported ${merged.toLocaleString()} records${pushedToCloud ? ' and added them to the spreadsheet' : ''}. Reloading…`);
      setTimeout(() => window.location.reload(), 1100);
    } catch (e2) {
      err(e2.message || 'CSV import failed.');
      setBusy(null);
    }
  }

  function disconnect() {
    setCloudUrl('');
    setConn(false);
    setUrl('');
    setSetup(true);
    ok('Disconnected. Your data stays on this device.');
  }

  async function copyScript() {
    try { await navigator.clipboard.writeText(APPS_SCRIPT); ok('Apps Script copied to clipboard.'); }
    catch { err('Copy failed — select the text manually.'); }
  }

  async function copyManifest() {
    try { await navigator.clipboard.writeText(MANIFEST); ok('appsscript.json copied to clipboard.'); }
    catch { err('Copy failed — select the text manually.'); }
  }

  return (
    <div style={S.backdrop} onClick={e => { if (e.target === e.currentTarget) onClose(); }}>
      <div style={S.sheet}>
        <div style={S.head}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 9 }}>
            <Cloud size={20} color={A} />
            <span style={S.title}>Cloud Sync</span>
          </div>
          <button style={S.close} onClick={onClose}><X size={18} /></button>
        </div>

        <div style={S.body}>
          <p style={S.lead}>
            Sync every app across your devices through a Google Sheet you own. Connect the same
            link on each device and they share one database.
          </p>

          {/* Setup instructions */}
          <button style={S.setupToggle} onClick={() => setSetup(s => !s)}>
            {showSetup ? <ChevronDown size={16} /> : <ChevronRight size={16} />}
            One-time setup &amp; how sharing works
          </button>
          {showSetup && (
            <div style={S.setupBox}>
              <ol style={S.ol}>
                <li>
                  <a href="https://sheets.new" target="_blank" rel="noreferrer" style={S.link}>
                    Create a new Google Sheet ↗
                  </a> (opens in a new tab).
                </li>
                <li>Open <b>Extensions ▸ Apps Script</b>, delete any code, paste the script below, and <b>Save</b> (disk icon).</li>
                <li><b>Deploy ▸ New deployment ▸</b> gear ▸ <b>Web app.</b> Set <b>Execute as: Me</b> and <b>Who has access: Anyone</b>, then <b>Deploy</b>.</li>
                <li>
                  Click <b>Authorize access</b> → pick your account. If you see
                  <b> “Google hasn’t verified this app”</b>, that’s expected — it’s your own script.
                  Click <b>Advanced ▸ Go to (your project) (unsafe) ▸ Allow.</b>
                </li>
                <li>Copy the <b>Web app URL</b> (ends in <code>/exec</code>) and paste it below.</li>
                <li><b>To share:</b> give that same URL to your other devices/instances — anyone with the link reads &amp; writes this sheet, so keep it private.</li>
              </ol>
              <button style={S.copyBtn} onClick={copyScript}><Copy size={13} /> Copy Apps Script</button>
              <pre style={S.code}>{APPS_SCRIPT}</pre>

              <div style={S.note}>
                🔒 <b>Limit access to just this sheet (recommended).</b> By default Google asks
                for access to all your spreadsheets. To restrict it to only this one:
                <ol style={{ ...S.ol, marginTop: 6 }}>
                  <li>In Apps Script, <b>Project Settings</b> (gear) → tick <b>“Show appsscript.json manifest file”</b>.</li>
                  <li>Open <b>appsscript.json</b> and add the <code>oauthScopes</code> line below, then Save.</li>
                  <li>Re-deploy (<b>Deploy ▸ Manage deployments ▸</b> edit ▸ <b>New version</b>) and re-authorize — now it only asks for <i>this</i> spreadsheet.</li>
                </ol>
              </div>
              <button style={S.copyBtn} onClick={copyManifest}><Copy size={13} /> Copy appsscript.json</button>
              <pre style={S.code}>{MANIFEST}</pre>
            </div>
          )}

          {/* URL field */}
          <label style={S.label}>Web App URL (the shared link)</label>
          <div style={{ display: 'flex', gap: 8 }}>
            <input
              style={S.input}
              placeholder="https://script.google.com/macros/s/…/exec"
              value={url}
              onChange={e => setUrl(e.target.value)}
            />
            <button style={S.connectBtn(!!url.trim() && busy !== 'connect')} onClick={handleConnect} disabled={!url.trim() || busy === 'connect'}>
              {busy === 'connect' ? <Loader2 size={15} /> : <Link2 size={15} />}
              {connected ? 'Update' : 'Connect'}
            </button>
          </div>

          {connected && (
            <>
              <div style={S.statusRow}>
                <Check size={14} color="#22C55E" />
                <span>Connected{last ? ` · last synced ${new Date(last).toLocaleString()}` : ''}</span>
              </div>

              {/* Primary actions */}
              {!confirmLoad ? (
                <div style={{ display: 'flex', gap: 10, marginTop: 12 }}>
                  <button style={S.action} onClick={() => { setCL(true); setMsg(null); }} disabled={!!busy}>
                    <Download size={16} /> Load from sheet
                  </button>
                  <button style={S.action} onClick={doSave} disabled={!!busy}>
                    {busy === 'save' ? <Loader2 size={16} /> : <Upload size={16} />} Save to sheet
                  </button>
                </div>
              ) : (
                <div style={S.warnBox}>
                  <div style={S.warnHead}><AlertTriangle size={16} color="#F59E0B" /> This replaces ALL data on this device with the spreadsheet’s.</div>
                  <div style={S.warnSub}>It can’t be undone. Export a CSV backup of this device first.</div>
                  <button style={S.exportBtn} onClick={exportCsv}><FileDown size={14} /> Export CSV backup</button>
                  <div style={{ display: 'flex', gap: 10, marginTop: 10 }}>
                    <button style={S.ghost} onClick={() => setCL(false)}>Cancel</button>
                    <button style={S.danger} onClick={doLoad}>{busy === 'load' ? 'Loading…' : 'Replace & load'}</button>
                  </div>
                </div>
              )}

              {/* Auto-sync */}
              <div style={S.autoRow}>
                <div>
                  <div style={{ fontSize: 14, color: '#E5E7EB', fontWeight: 600 }}>Auto-sync</div>
                  <div style={{ fontSize: 12, color: '#9CA3AF', marginTop: 2 }}>Pull on open, push when you leave. Last write wins.</div>
                </div>
                <button role="switch" aria-checked={auto} onClick={() => setAuto(a => !a)} style={S.toggle(auto)}>
                  <span style={S.knob(auto)} />
                </button>
              </div>

              {/* CSV + disconnect */}
              <div style={{ display: 'flex', gap: 10, marginTop: 14 }}>
                <button style={S.minor} onClick={() => fileRef.current?.click()} disabled={!!busy}>
                  {busy === 'csv' ? <Loader2 size={14} /> : <FileUp size={14} />} Import CSV
                </button>
                <button style={S.minor} onClick={exportCsv} disabled={!!busy}><FileDown size={14} /> Export CSV</button>
                <button style={{ ...S.minor, color: '#F87171' }} onClick={disconnect}><Trash2 size={14} /> Disconnect</button>
              </div>
              <input ref={fileRef} type="file" accept=".csv,text/csv" onChange={handleCsvFile} style={{ display: 'none' }} />
            </>
          )}

          {msg && <div style={{ ...S.msg, color: msg.kind === 'err' ? '#F87171' : '#34D399' }}>{msg.text}</div>}
        </div>
      </div>
    </div>
  );
}

const S = {
  backdrop: { position: 'fixed', inset: 0, zIndex: 1000, background: 'rgba(4,6,18,0.7)', backdropFilter: 'blur(4px)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 16 },
  sheet: { width: '100%', maxWidth: 560, maxHeight: '90vh', display: 'flex', flexDirection: 'column', background: '#0E1124', border: '1px solid #232744', borderRadius: 18, overflow: 'hidden', boxShadow: '0 24px 80px rgba(0,0,0,0.6)' },
  head: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '16px 18px', borderBottom: '1px solid #1d2138', flexShrink: 0 },
  title: { fontSize: 18, fontWeight: 800, color: '#F9FAFB' },
  close: { background: '#1a1e33', border: 'none', color: '#9CA3AF', width: 32, height: 32, borderRadius: 8, display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' },
  body: { padding: 18, overflowY: 'auto' },
  lead: { fontSize: 13.5, color: '#9CA3AF', lineHeight: 1.5, margin: '0 0 14px' },
  setupToggle: { display: 'flex', alignItems: 'center', gap: 6, background: 'none', border: 'none', color: A, fontSize: 13.5, fontWeight: 600, cursor: 'pointer', padding: 0, marginBottom: 10 },
  setupBox: { background: '#0a0d1c', border: '1px solid #1d2138', borderRadius: 12, padding: 14, marginBottom: 16 },
  ol: { margin: 0, paddingLeft: 18, color: '#C7CBD9', fontSize: 13, lineHeight: 1.6 },
  link: { color: '#A5B4FC', fontWeight: 700, textDecoration: 'underline' },
  copyBtn: { display: 'inline-flex', alignItems: 'center', gap: 6, marginTop: 12, padding: '7px 12px', background: '#1a1e33', border: '1px solid #2a2f4d', borderRadius: 8, color: A, fontSize: 12.5, fontWeight: 600, cursor: 'pointer' },
  code: { marginTop: 10, marginBottom: 0, padding: 12, background: '#06080f', border: '1px solid #1d2138', borderRadius: 8, color: '#9aa3c0', fontSize: 10.5, lineHeight: 1.5, overflowX: 'auto', whiteSpace: 'pre', maxHeight: 180 },
  note: { marginTop: 14, padding: 12, background: 'rgba(99,102,241,0.08)', border: '1px solid rgba(99,102,241,0.25)', borderRadius: 8, color: '#C7CBD9', fontSize: 12.5, lineHeight: 1.5 },
  label: { display: 'block', fontSize: 12, color: '#8b90a8', textTransform: 'uppercase', letterSpacing: '0.05em', fontWeight: 600, margin: '4px 0 6px' },
  input: { flex: 1, padding: '11px 12px', background: '#0a0d1c', border: '1px solid #2a2f4d', borderRadius: 10, color: '#F9FAFB', fontSize: 15, outline: 'none', minWidth: 0 },
  connectBtn: (en) => ({ display: 'flex', alignItems: 'center', gap: 6, padding: '0 16px', background: en ? A : '#2a2f4d', color: '#fff', border: 'none', borderRadius: 10, fontSize: 14, fontWeight: 700, cursor: en ? 'pointer' : 'not-allowed', whiteSpace: 'nowrap' }),
  statusRow: { display: 'flex', alignItems: 'center', gap: 7, marginTop: 14, fontSize: 13, color: '#C7CBD9' },
  action: { flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 7, padding: '12px 0', background: '#1a1e33', border: '1px solid #2a2f4d', borderRadius: 11, color: '#F9FAFB', fontSize: 14, fontWeight: 700, cursor: 'pointer' },
  warnBox: { marginTop: 12, background: 'rgba(245,158,11,0.08)', border: '1px solid rgba(245,158,11,0.3)', borderRadius: 12, padding: 14 },
  warnHead: { display: 'flex', alignItems: 'center', gap: 8, fontSize: 13.5, fontWeight: 700, color: '#F9FAFB', lineHeight: 1.4 },
  warnSub: { fontSize: 12.5, color: '#C7CBD9', margin: '6px 0 10px', lineHeight: 1.45 },
  exportBtn: { display: 'inline-flex', alignItems: 'center', gap: 7, padding: '9px 14px', background: '#1a1e33', border: '1px solid #2a2f4d', borderRadius: 9, color: '#34D399', fontSize: 13, fontWeight: 700, cursor: 'pointer' },
  ghost: { flex: 1, padding: '10px 0', background: 'none', border: '1px solid #2a2f4d', borderRadius: 9, color: '#C7CBD9', fontSize: 13.5, fontWeight: 600, cursor: 'pointer' },
  danger: { flex: 1, padding: '10px 0', background: '#DC2626', border: 'none', borderRadius: 9, color: '#fff', fontSize: 13.5, fontWeight: 700, cursor: 'pointer' },
  autoRow: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 12, marginTop: 16, paddingTop: 14, borderTop: '1px solid #1d2138' },
  toggle: (on) => ({ width: 46, height: 26, borderRadius: 13, border: 'none', position: 'relative', background: on ? A : '#2a2f4d', cursor: 'pointer', flexShrink: 0 }),
  knob: (on) => ({ position: 'absolute', top: 3, left: on ? 23 : 3, width: 20, height: 20, borderRadius: '50%', background: '#fff', transition: 'left 0.2s' }),
  minor: { flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6, padding: '10px 0', background: 'none', border: '1px solid #2a2f4d', borderRadius: 9, color: '#C7CBD9', fontSize: 12.5, fontWeight: 600, cursor: 'pointer' },
  msg: { fontSize: 13, fontWeight: 500, marginTop: 14, lineHeight: 1.45 },
};
