// Cross-app: estimate calories burned in the gym on a given day so NutriCore can fold
// them into expenditure. Strength training ≈ 5 METs; kcal = MET × bodyweightKg × hours.
import { getAllSessions } from '../db';

const STRENGTH_MET = 5;

export async function getGymCaloriesForDate(dateStr, weightKg = 75) {
  try {
    const all = await getAllSessions();
    let secs = 0;
    let workouts = 0;
    for (const s of all) {
      if (!s.date) continue;
      const day = new Date(s.date).toLocaleDateString('sv-SE');
      if (day !== dateStr) continue;
      secs += s.duration || 0;
      workouts++;
    }
    const kcal = Math.round(STRENGTH_MET * (weightKg || 75) * (secs / 3600));
    return { kcal, minutes: Math.round(secs / 60), workouts };
  } catch {
    return { kcal: 0, minutes: 0, workouts: 0 };
  }
}
