// Google Sheets cloud sync.
//
// Why a Google Apps Script Web App (not the Sheets API / Firebase): it needs zero
// backend, no API keys, and no per-user OAuth setup. The user deploys a tiny script
// bound to their own Sheet as a Web App ("anyone can access"), which hands back one
// URL. That URL is the shared database link — paste it into any device/instance and
// they all read/write the same sheet. Data is stored as rows [db, store, key, json],
// which round-trips losslessly to IndexedDB AND to CSV.

import { buildBackup, restoreBackup, mergeBackup, BACKUP_FORMAT } from './backup';

const LS_URL  = 'cloud_sync_url';
const LS_LAST = 'cloud_sync_last';
const LS_AUTO = 'cloud_sync_auto';

// Google Sheets caps a single cell at ~50k chars; skip records bigger than this when
// pushing to the cloud (e.g. progress-photo data URLs). They still live locally and in
// CSV/JSON backups — just not in the spreadsheet.
const CELL_LIMIT = 45000;

export function getCloudUrl() { return localStorage.getItem(LS_URL) || ''; }
export function setCloudUrl(url) {
  if (url) localStorage.setItem(LS_URL, url.trim());
  else localStorage.removeItem(LS_URL);
}
export function getLastSync() { return localStorage.getItem(LS_LAST) || ''; }
function markSynced() { localStorage.setItem(LS_LAST, new Date().toISOString()); }
export function isAutoSync() { return localStorage.getItem(LS_AUTO) === '1'; }
export function setAutoSync(on) { localStorage.setItem(LS_AUTO, on ? '1' : '0'); }

// ── Backup ⇄ flat rows ──────────────────────────────────────────────────────────
function recordKey(rec) {
  return String(rec?.id ?? rec?.key ?? rec?.date ?? rec?.foodId ?? rec?.barcode ?? '');
}

export function backupToRows(backup) {
  const rows = [];
  for (const [db, stores] of Object.entries(backup.data || {})) {
    if (!stores) continue;
    for (const [store, records] of Object.entries(stores)) {
      for (const rec of records || []) {
        rows.push({ db, store, key: recordKey(rec), data: JSON.stringify(rec) });
      }
    }
  }
  return rows;
}

export function rowsToBackup(rows) {
  const data = {};
  for (const r of rows || []) {
    let rec;
    try { rec = JSON.parse(r.data); } catch { continue; }
    (data[r.db] = data[r.db] || {});
    (data[r.db][r.store] = data[r.db][r.store] || []).push(rec);
  }
  return { format: BACKUP_FORMAT, version: 1, data };
}

// ── CSV ───────────────────────────────────────────────────────────────────────
function csvField(v) {
  const s = String(v ?? '');
  return /[",\n\r]/.test(s) ? `"${s.replace(/"/g, '""')}"` : s;
}
export function rowsToCsv(rows) {
  const head = 'db,store,key,data';
  const body = rows.map(r => [r.db, r.store, r.key, r.data].map(csvField).join(',')).join('\n');
  return `${head}\n${body}\n`;
}
export function parseCsv(text) {
  const rows = [];
  let field = '', record = [], inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const c = text[i];
    if (inQuotes) {
      if (c === '"') {
        if (text[i + 1] === '"') { field += '"'; i++; }
        else inQuotes = false;
      } else field += c;
    } else if (c === '"') inQuotes = true;
    else if (c === ',') { record.push(field); field = ''; }
    else if (c === '\n' || c === '\r') {
      if (c === '\r' && text[i + 1] === '\n') i++;
      record.push(field); field = '';
      if (record.length > 1 || record[0] !== '') rows.push(record);
      record = [];
    } else field += c;
  }
  if (field !== '' || record.length) { record.push(field); rows.push(record); }
  // Drop header, map to objects
  const out = [];
  for (let r = 0; r < rows.length; r++) {
    const [db, store, key, ...rest] = rows[r];
    if (r === 0 && db === 'db') continue; // header
    if (!db) continue;
    out.push({ db, store, key, data: rest.join(',') });
  }
  return out;
}

// ── Network (Apps Script Web App) ───────────────────────────────────────────────
async function pullRows(url) {
  const res = await fetch(url, { method: 'GET' });
  if (!res.ok) throw new Error(`Spreadsheet returned ${res.status}`);
  const json = await res.json();
  return json.rows || [];
}
async function pushRows(url, rows, mode) {
  // text/plain avoids a CORS preflight that Apps Script can't answer.
  const res = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'text/plain;charset=utf-8' },
    body: JSON.stringify({ rows, mode }),
  });
  if (!res.ok) throw new Error(`Spreadsheet returned ${res.status}`);
  return res.json();
}

// ── Public sync operations ──────────────────────────────────────────────────────

// Replace the spreadsheet's contents with everything on this device.
export async function pushAll(url = getCloudUrl()) {
  if (!url) throw new Error('No spreadsheet connected.');
  const backup = await buildBackup();
  const all = backupToRows(backup);
  const rows = all.filter(r => r.data.length <= CELL_LIMIT);
  const skipped = all.length - rows.length;
  await pushRows(url, rows, 'replace');
  markSynced();
  return { pushed: rows.length, skipped };
}

// Replace THIS DEVICE's data with the spreadsheet's contents.
export async function pullAll(url = getCloudUrl()) {
  if (!url) throw new Error('No spreadsheet connected.');
  const rows = await pullRows(url);
  const restored = await restoreBackup(rowsToBackup(rows));
  markSynced();
  return { restored };
}

// Validate a URL by attempting a read.
export async function testConnection(url) {
  const rows = await pullRows(url);
  return { ok: true, rows: rows.length };
}

// Merge CSV rows into local data AND the spreadsheet (adds, does not wipe).
export async function importCsvRows(rows, url = getCloudUrl()) {
  const merged = await mergeBackup(rowsToBackup(rows));
  if (url) await pushRows(url, rows, 'merge');
  if (url) markSynced();
  return { merged, pushedToCloud: !!url };
}

// Build a CSV string of everything on this device (for the pre-overwrite backup).
export async function buildCsv() {
  const backup = await buildBackup();
  return rowsToCsv(backupToRows(backup));
}

export function downloadCsv(csv, filename) {
  const blob = new Blob([csv], { type: 'text/csv' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename || `pranav-tools-${new Date().toISOString().slice(0, 10)}.csv`;
  document.body.appendChild(a);
  a.click();
  a.remove();
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}

// The Apps Script the user pastes into their Sheet (shown in the UI, copyable).
export const APPS_SCRIPT = `// Pranav's Tools — Sheets sync backend. Paste into Extensions ▸ Apps Script, then
// Deploy ▸ New deployment ▸ Web app ▸ Execute as: Me ▸ Who has access: Anyone.
const TAB = 'data';
function sheet_() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sh = ss.getSheetByName(TAB);
  if (!sh) { sh = ss.insertSheet(TAB); sh.appendRow(['db','store','key','data']); }
  return sh;
}
function read_() {
  const v = sheet_().getDataRange().getValues(); v.shift();
  return v.filter(r => r[0]).map(r => ({ db:r[0], store:r[1], key:String(r[2]), data:r[3] }));
}
function write_(rows, mode) {
  const sh = sheet_();
  let out = rows;
  if (mode === 'merge') {
    const cur = read_(), idx = {};
    cur.forEach((r,i) => idx[r.db+'|'+r.store+'|'+r.key] = i);
    rows.forEach(r => { const k=r.db+'|'+r.store+'|'+r.key; if (k in idx) cur[idx[k]]=r; else cur.push(r); });
    out = cur;
  }
  sh.clear(); sh.appendRow(['db','store','key','data']);
  if (out.length) sh.getRange(2,1,out.length,4).setValues(out.map(r => [r.db,r.store,r.key,r.data]));
}
function json_(o){ return ContentService.createTextOutput(JSON.stringify(o)).setMimeType(ContentService.MimeType.JSON); }
function doGet(){ return json_({ rows: read_() }); }
function doPost(e){
  const b = JSON.parse(e.postData.contents || '{}');
  write_(b.rows || [], b.mode || 'replace');
  return json_({ ok:true, count:(b.rows||[]).length });
}`;
