import { useState, useEffect } from 'react';
import { Search, Plus, Trash2 } from 'lucide-react';
import { getAllFoods, saveFood } from './db';
import { searchFoods } from './nutrition';

const CATEGORY_EMOJI = {
  protein: '🥩', dairy: '🥛', grain: '🌾', vegetable: '🥦',
  fruit: '🍎', fat: '🫒', beverage: '☕', supplement: '💊', other: '🟤',
};

export default function RecipeModal({ onClose, onSaved }) {
  const [name,        setName]        = useState('');
  const [servings,    setServings]    = useState(1);
  const [ingredients, setIngredients] = useState([]); // [{food, amountG}]
  const [query,       setQuery]       = useState('');
  const [allFoods,    setAllFoods]    = useState([]);
  const [results,     setResults]     = useState([]);
  const [saving,      setSaving]      = useState(false);

  useEffect(() => { getAllFoods().then(setAllFoods); }, []);

  useEffect(() => {
    if (query.trim()) {
      setResults(searchFoods(allFoods, query).slice(0, 20));
    } else {
      setResults([]);
    }
  }, [query, allFoods]);

  function addIngredient(food) {
    setIngredients(prev => {
      const existing = prev.find(i => i.food.id === food.id);
      if (existing) {
        return prev.map(i => i.food.id === food.id ? { ...i, amountG: i.amountG + 100 } : i);
      }
      return [...prev, { food, amountG: 100 }];
    });
    setQuery('');
    setResults([]);
  }

  function updateAmount(foodId, val) {
    const n = Math.max(1, Number(val));
    setIngredients(prev => prev.map(i => i.food.id === foodId ? { ...i, amountG: n } : i));
  }

  function removeIngredient(foodId) {
    setIngredients(prev => prev.filter(i => i.food.id !== foodId));
  }

  const totals = ingredients.reduce((acc, { food, amountG }) => {
    const s = amountG / 100;
    acc.kcal     += (food.kcal     || 0) * s;
    acc.proteinG += (food.proteinG || 0) * s;
    acc.carbsG   += (food.carbsG   || 0) * s;
    acc.fatG     += (food.fatG     || 0) * s;
    acc.fiberG   += (food.fiberG   || 0) * s;
    return acc;
  }, { kcal: 0, proteinG: 0, carbsG: 0, fatG: 0, fiberG: 0 });

  const srv = Math.max(1, servings);
  const perServing = {
    kcal:     totals.kcal     / srv,
    proteinG: totals.proteinG / srv,
    carbsG:   totals.carbsG   / srv,
    fatG:     totals.fatG     / srv,
    fiberG:   totals.fiberG   / srv,
  };

  async function handleSave() {
    if (!name.trim() || ingredients.length === 0) return;
    setSaving(true);
    const food = {
      name:        name.trim(),
      brand:       'Recipe',
      category:    'other',
      sourceDb:    'custom',
      kcal:        parseFloat(perServing.kcal.toFixed(1)),
      proteinG:    parseFloat(perServing.proteinG.toFixed(1)),
      carbsG:      parseFloat(perServing.carbsG.toFixed(1)),
      fatG:        parseFloat(perServing.fatG.toFixed(1)),
      fiberG:      parseFloat(perServing.fiberG.toFixed(1)),
      sugarG:      0,
      sodiumMg:    0,
      servingSizeG: 100,
      isCustom:    true,
    };
    const id = await saveFood(food);
    setSaving(false);
    onSaved({ ...food, id });
  }

  return (
    <div className="nc-modal-overlay" onClick={e => { if (e.target === e.currentTarget) onClose(); }}>
      <div className="nc-picker">
        <div className="nc-picker-header">
          <div className="nc-picker-title-row">
            <span className="nc-picker-title">Create Recipe</span>
            <button className="nc-picker-close" onClick={onClose}>✕</button>
          </div>

          {/* Name + servings row */}
          <div style={{ display: 'flex', gap: 8, marginBottom: 12, alignItems: 'center' }}>
            <input
              className="nc-amount-input"
              style={{ flex: 1, fontSize: 16, padding: '8px 12px', textAlign: 'left' }}
              placeholder="Recipe name…"
              value={name}
              onChange={e => setName(e.target.value)}
            />
            <div style={{ display: 'flex', alignItems: 'center', gap: 6, flexShrink: 0 }}>
              <span style={{ fontSize: 12, color: 'var(--nc-text2)', whiteSpace: 'nowrap' }}>Servings</span>
              <input
                type="number" min="1" step="1"
                className="nc-amount-input"
                style={{ width: 52, padding: '8px 6px', fontSize: 16 }}
                value={servings}
                onChange={e => setServings(Math.max(1, Number(e.target.value)))}
              />
            </div>
          </div>

          {/* Ingredient search */}
          <div className="nc-search-bar" style={{ marginBottom: 12 }}>
            <Search size={15} className="nc-search-icon" />
            <input
              placeholder="Search ingredients to add…"
              value={query}
              onChange={e => setQuery(e.target.value)}
            />
            {query && (
              <button className="nc-search-clear" onClick={() => setQuery('')}>✕</button>
            )}
          </div>
        </div>

        <div className="nc-picker-list">
          {/* Search results */}
          {results.length > 0 && (
            <div style={{ borderBottom: '1px solid var(--nc-border)' }}>
              {results.map(food => (
                <div key={food.id} className="nc-food-row" onClick={() => addIngredient(food)}>
                  <div className={`nc-food-icon cat-${food.category}`}>
                    {CATEGORY_EMOJI[food.category] || '🍽️'}
                  </div>
                  <div className="nc-food-body">
                    <div className="nc-food-name">{food.name}</div>
                    {food.brand && food.brand !== 'Recipe' && (
                      <div className="nc-food-brand">{food.brand}</div>
                    )}
                  </div>
                  <div className="nc-food-meta">
                    <div className="nc-food-kcal">{Math.round(food.kcal)}</div>
                    <div className="nc-food-per">kcal/100g</div>
                  </div>
                  <Plus size={17} style={{ color: 'var(--nc-accent)', flexShrink: 0 }} />
                </div>
              ))}
            </div>
          )}

          {/* Current ingredients */}
          {ingredients.length === 0 && results.length === 0 && (
            <div className="nc-picker-empty">Search above to add ingredients</div>
          )}

          {ingredients.map(({ food, amountG }) => (
            <div key={food.id} className="nc-food-row" style={{ alignItems: 'center' }}>
              <div className={`nc-food-icon cat-${food.category}`}>
                {CATEGORY_EMOJI[food.category] || '🍽️'}
              </div>
              <div className="nc-food-body">
                <div className="nc-food-name">{food.name}</div>
                <div className="nc-food-brand">{Math.round(food.kcal * amountG / 100)} kcal</div>
              </div>
              <input
                type="number" min="1" step="1"
                className="nc-amount-input"
                style={{ width: 60, padding: '4px 6px', fontSize: 16 }}
                value={amountG}
                onChange={e => updateAmount(food.id, e.target.value)}
              />
              <span style={{ fontSize: 11, color: 'var(--nc-text3)', marginLeft: 3 }}>g</span>
              <button
                style={{ marginLeft: 8, color: 'var(--nc-text3)', flexShrink: 0 }}
                onClick={() => removeIngredient(food.id)}
              >
                <Trash2 size={15} />
              </button>
            </div>
          ))}

          {/* Per-serving nutrition preview */}
          {ingredients.length > 0 && (
            <div style={{ padding: '12px 16px', borderTop: '1px solid var(--nc-border)' }}>
              <div style={{
                fontSize: 10, color: 'var(--nc-text3)', marginBottom: 8,
                textTransform: 'uppercase', letterSpacing: '0.4px',
              }}>
                Per Serving ({srv} serving{srv !== 1 ? 's' : ''} total)
              </div>
              <div className="nc-preview-grid">
                {[
                  { label: 'kcal',    val: Math.round(perServing.kcal) },
                  { label: 'protein', val: `${Math.round(perServing.proteinG)}g` },
                  { label: 'carbs',   val: `${Math.round(perServing.carbsG)}g` },
                  { label: 'fat',     val: `${Math.round(perServing.fatG)}g` },
                ].map(({ label, val }) => (
                  <div key={label} className="nc-preview-card">
                    <div className="nc-preview-val">{val}</div>
                    <div className="nc-preview-lbl">{label}</div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        <div style={{ padding: '12px 16px', borderTop: '1px solid var(--nc-border)', flexShrink: 0 }}>
          <button
            className="nc-log-btn"
            disabled={!name.trim() || ingredients.length === 0 || saving}
            onClick={handleSave}
          >
            {saving ? 'Saving…' : 'Save Recipe as Food'}
          </button>
        </div>
      </div>
    </div>
  );
}
